function Greeting() {
  const name = 'Alice';
  const age = 25;
  const isLoggedIn = true;

  return (
    <div>
      <h1>Hello, {name}!</h1>
      <p>You are {age} years old.</p>
      <p>Status: {isLoggedIn ? 'Online' : 'Offline'}</p>
      <p>2 + 2 = {2 + 2}</p>
    </div>
  );
}
